{
  "name": "milu",
  "full_name": "MILU — A Multi-task Indic Language Understanding Benchmark",
  "year": 2024,
  "domain": "Multilingual Indic language understanding and culturally specific knowledge evaluation",
  "porting_strategy": "ground_up",
  "languages": [
    "bn",
    "gu",
